// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





// Place helper components here if needed

export default function Component(props: Props) {
  // Actions
  const submit = useAction<ActionSubmitPayload>('submit');

  // State
  const [currentStep, setCurrentStep] = useState(1);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState('');
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');

  // Validation
  const nameError = name.trim() === '' ? 'Name is required' : '';
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  const emailError = email.trim() === '' ? 'Email is required' : !emailRegex.test(email) ? 'Enter a valid email address' : '';
  const isStep1Valid = !nameError && !emailError;
  const isStep2Valid = satisfaction !== '';
  const isStep3Valid = true; // Optional step

  // Step definitions
  const totalSteps = 5; // Including final review step

  // Navigation handlers
  const handleNext = useCallback(() => {
    if (currentStep === 1 && !isStep1Valid) return;
    if (currentStep === 2 && !isStep2Valid) return;
    if (currentStep < totalSteps) {
      setCurrentStep(currentStep + 1);
    }
  }, [currentStep, isStep1Valid, isStep2Valid]);

  const handleBack = useCallback(() => {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
    }
  }, [currentStep]);

  const handleSubmit = useCallback(() => {
    if (isStep1Valid) {
      submit({
        name: name.trim(),
        email: email.trim(),
        satisfaction: parseInt(satisfaction, 10),
        features,
        comments: comments.trim(),
      });
    }
  }, [name, email, satisfaction, features, comments, isStep1Valid, submit]);

  const handleFeatureChange = useCallback((feature: string) => {
    setFeatures((prev) =>
      prev.includes(feature) ? prev.filter((f) => f !== feature) : [...prev, feature]
    );
  }, []);

  // Satisfaction options from props
  const satisfactionOptions = props.satisfactionLabels.map((label, idx) => ({
    value: String(idx + 1),
    label,
  }));

  return (
    <Container maxWidth="lg" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Progress Bar */}
        <Box>
          <Progress
            value={currentStep}
            max={totalSteps}
            variant="default"
            size="md"
            showLabel
          />
        </Box>

        {/* Step Content */}
        <Card padding="var(--ggui-spacing-6)" shadow="md">
          <Stack gap="var(--ggui-spacing-4)">
            {currentStep === 1 && (
              <>
                <Heading level={3}>Step 1 of 5: Personal Information</Heading>
                <Stack gap="var(--ggui-spacing-4)">
                  <Input
                    label="Full Name"
                    placeholder="Enter your full name"
                    value={name}
                    onChange={setName}
                    error={nameError}
                    required
                  />
                  <Input
                    label="Email Address"
                    type="email"
                    placeholder="you@example.com"
                    value={email}
                    onChange={setEmail}
                    error={emailError}
                    required
                  />
                </Stack>
              </>
            )}

            {currentStep === 2 && (
              <>
                <Heading level={3}>Step 2 of 5: Satisfaction Rating</Heading>
                <Stack gap="var(--ggui-spacing-3)">
                  <RadioGroup
                    label="How satisfied are you overall?"
                    value={satisfaction}
                    onChange={setSatisfaction}
                    options={satisfactionOptions}
                    direction="vertical"
                  />
                </Stack>
              </>
            )}

            {currentStep === 3 && (
              <>
                <Heading level={3}>Step 3 of 5: Features Interest</Heading>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                  Select all features you're interested in:
                </Text>
                <Stack gap="var(--ggui-spacing-2)">
                  {props.featureOptions.map((feature) => (
                    <Checkbox
                      key={feature}
                      label={feature}
                      checked={features.includes(feature)}
                      onChange={() => handleFeatureChange(feature)}
                    />
                  ))}
                </Stack>
              </>
            )}

            {currentStep === 4 && (
              <>
                <Heading level={3}>Step 4 of 5: Additional Comments</Heading>
                <Stack gap="var(--ggui-spacing-3)">
                  <TextArea
                    label="Comments"
                    placeholder="Share any additional feedback or comments..."
                    value={comments}
                    onChange={setComments}
                    rows={6}
                    maxLength={500}
                    showCount
                  />
                </Stack>
              </>
            )}

            {currentStep === 5 && (
              <>
                <Heading level={3}>Step 5 of 5: Review Your Answers</Heading>
                <Stack gap="var(--ggui-spacing-4)">
                  <Card padding="var(--ggui-spacing-4)" shadow="sm" border>
                    <Stack gap="var(--ggui-spacing-3)">
                      <Box>
                        <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Full Name</Text>
                        <Text>{name || '—'}</Text>
                      </Box>
                      <Divider />
                      <Box>
                        <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Email Address</Text>
                        <Text>{email || '—'}</Text>
                      </Box>
                      <Divider />
                      <Box>
                        <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Satisfaction Rating</Text>
                        <Text>{satisfaction ? props.satisfactionLabels[parseInt(satisfaction, 10) - 1] : '—'}</Text>
                      </Box>
                      <Divider />
                      <Box>
                        <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Features Interested In</Text>
                        <Stack gap="var(--ggui-spacing-1)">
                          {features.length > 0 ? features.map((f) => <Text key={f}>• {f}</Text>) : <Text>—</Text>}
                        </Stack>
                      </Box>
                      <Divider />
                      <Box>
                        <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Additional Comments</Text>
                        <Text>{comments || '—'}</Text>
                      </Box>
                    </Stack>
                  </Card>
                </Stack>
              </>
            )}
          </Stack>
        </Card>

        {/* Navigation Buttons */}
        <Row justify="between" gap="var(--ggui-spacing-3)">
          <Button
            variant="outline"
            onClick={handleBack}
            disabled={currentStep === 1}
          >
            Back
          </Button>
           {currentStep < totalSteps ? (
            <Button
              variant="primary"
              onClick={handleNext}
              disabled={
                (currentStep === 1 && !isStep1Valid) ||
                (currentStep === 2 && !isStep2Valid)
              }
            >
              Next
            </Button>
          ) : (
            <Button
              variant="primary"
              onClick={handleSubmit}
              disabled={!isStep1Valid}
            >
              Submit
            </Button>
          )}
        </Row>
      </Stack>
    </Container>
  );
}

