// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string } };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };




// Helper sub-component: Task Card
interface TaskCardProps {
  task: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string };
  columns: Array<{ id?: string; name?: string }>;
  onMove: (taskId: string, newColumn: string) => void;
  onEdit: (taskId: string, newTitle: string) => void;
}

function TaskCard({ task, columns, onMove, onEdit }: TaskCardProps) {
  const [isEditing, setIsEditing] = useState(false);
  const [editTitle, setEditTitle] = useState(task.title || '');

  const priorityColor: Record<string, string> = {
    low: 'var(--ggui-color-success-100)',
    medium: 'var(--ggui-color-warning-100)',
    high: 'var(--ggui-color-error-100)',
  };

  const priorityTextColor: Record<string, string> = {
    low: 'var(--ggui-color-success-700)',
    medium: 'var(--ggui-color-warning-700)',
    high: 'var(--ggui-color-error-700)',
  };

  const handleSave = () => {
    if (editTitle.trim()) {
      onEdit(task.id || '', editTitle);
    }
    setIsEditing(false);
  };

  return (
    <Card padding="var(--ggui-spacing-3)" shadow="sm" radius="md">
      <Stack gap="var(--ggui-spacing-2)">
        {isEditing ? (
          <Stack gap="var(--ggui-spacing-2)">
            <Input
              label="Task title"
              value={editTitle}
              onChange={setEditTitle}
              placeholder="Enter task title"
              size="sm"
            />
            <Row gap="var(--ggui-spacing-1)" justify="end">
              <Button size="xs" variant="ghost" onClick={() => { setIsEditing(false); setEditTitle(task.title || ''); }}>
                Cancel
              </Button>
              <Button size="xs" variant="primary" onClick={handleSave}>
                Save
              </Button>
            </Row>
          </Stack>
        ) : (
          <>
            <Row justify="between" align="center">
              <Text variant="body" weight="medium" style={{ flex: 1 }} onDoubleClick={() => setIsEditing(true)}>
                {task.title || 'Untitled Task'}
              </Text>
              <Button size="xs" variant="ghost" onClick={() => setIsEditing(true)}>
                <Icon name="edit" size={14} />
              </Button>
            </Row>
            {task.priority && (
              <Box
                padding="var(--ggui-spacing-1) var(--ggui-spacing-2)"
                background={priorityColor[task.priority] || 'var(--ggui-color-surfaceVariant)'}
                borderRadius="var(--ggui-shape-radius-sm)"
              >
                <Text
                  variant="caption"
                  weight="medium"
                  color={priorityTextColor[task.priority] || 'var(--ggui-color-onSurfaceVariant)'}
                >
                  {task.priority.charAt(0).toUpperCase() + task.priority.slice(1)}
                </Text>
              </Box>
            )}
            <Row gap="var(--ggui-spacing-2)" align="center" justify="between">
              <Row gap="var(--ggui-spacing-1)" align="center">
                {task.assignee && (
                  <Avatar name={task.assignee} size="sm" shape="circle" />
                )}
                {task.dueDate && (
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                    {new Date(task.dueDate).toLocaleDateString()}
                  </Text>
                )}
              </Row>
              <Dropdown
                trigger={<Button size="xs" variant="ghost"><Icon name="chevron-down" size={14} /></Button>}
                options={columns.map(col => ({ value: col.id || '', label: col.name || '' }))}
                value={task.column || ''}
                onChange={(newColumn) => onMove(task.id || '', newColumn)}
                placement="bottom-end"
              />
            </Row>
          </>
        )}
      </Stack>
    </Card>
  );
}


export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate'); // Called when a task is moved, edited, or created. Payload: { action, taskId, data }

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged'); // A task was moved, edited, or created by another user — update it in the board

  // State management
  const [tasks, setTasks] = useState(props.tasks);
  const [newTaskForm, setNewTaskForm] = useState<Record<string, { title: string; priority: 'low' | 'medium' | 'high' }>>({}); // One form per column

  // Sync props to local state
  useEffect(() => {
    setTasks(props.tasks);
  }, [props.tasks]);

  // Sync stream updates to local state
  useEffect(() => {
    if (taskChanged.latest) {
      const { action, task } = taskChanged.latest;
      if (action === 'delete' && task?.id) {
        setTasks(prev => prev.filter(t => t.id !== task.id));
      } else if (task?.id) {
        setTasks(prev => {
          const existing = prev.findIndex(t => t.id === task.id);
          if (existing >= 0) {
            return [...prev.slice(0, existing), task, ...prev.slice(existing + 1)];
          }
          return [...prev, task];
        });
      }
    }
  }, [taskChanged.latest]);

  // Calculate statistics
  const totalTasks = tasks.length;
  const completedTasks = tasks.filter(t => t.column === 'done').length;

  // Task handlers
  const handleMoveTask = (taskId: string, newColumn: string) => {
    setTasks(prev =>
      prev.map(t => t.id === taskId ? { ...t, column: newColumn } : t)
    );
    taskUpdate({ action: 'move', taskId, data: { column: newColumn } });
  };

  const handleEditTask = (taskId: string, newTitle: string) => {
    setTasks(prev =>
      prev.map(t => t.id === taskId ? { ...t, title: newTitle } : t)
    );
    taskUpdate({ action: 'edit', taskId, data: { column: tasks.find(t => t.id === taskId)?.column || 'todo' } });
  };

  const handleAddTask = (columnId: string) => {
    const form = newTaskForm[columnId];
    if (!form || !form.title.trim()) return;

    const newTask = {
      id: `task-${Date.now()}`,
      title: form.title,
      priority: form.priority,
      column: columnId,
    };
    setTasks(prev => [...prev, newTask]);
    taskUpdate({ action: 'create', taskId: newTask.id, data: { column: columnId } });
    setNewTaskForm(prev => ({ ...prev, [columnId]: { title: '', priority: 'medium' } }));
  };

  // Get tasks for a column
  const getColumnTasks = (columnId: string) => tasks.filter(t => t.column === columnId);

  return (
    <Container maxWidth="2xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Header */}
        <Stack gap="var(--ggui-spacing-3)">
          <Heading level={1} color="var(--ggui-color-onSurface)">Kanban Board</Heading>
          <Card padding="var(--ggui-spacing-4)" shadow="sm" background="var(--ggui-color-primary-50)">
            <Row gap="var(--ggui-spacing-4)" justify="start" align="center">
              <Box>
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Total Tasks</Text>
                <Text variant="bodyLarge" weight="bold" color="var(--ggui-color-primary-600)">{totalTasks}</Text>
              </Box>
              <Divider orientation="vertical" margin="0" />
              <Box>
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Completed</Text>
                <Text variant="bodyLarge" weight="bold" color="var(--ggui-color-success-600)">{completedTasks}</Text>
              </Box>
            </Row>
          </Card>
        </Stack>

        {/* Kanban Columns */}
        <Row gap="var(--ggui-spacing-4)" align="start" wrap>
          {props.columns.map(column => {
            const columnTasks = getColumnTasks(column.id || '');
            const form = newTaskForm[column.id || ''] || { title: '', priority: 'medium' };

            return (
              <Box
                key={column.id}
                padding="var(--ggui-spacing-4)"
