                        }))
                      }
                    >
                      + Add Task
                    </Button>
                  ) : (
                    <Stack gap="var(--ggui-spacing-2)">
                      <Input
                        label="Task title"
                        placeholder="New task title"
                        value={form.title}
                        onChange={title =>
                          setNewTaskForm(prev => ({
                            ...prev,
                            [column.id || '']: { ...form, title },
                          }))
                        }
                        size="sm"
                      />
                      <Select
                        label="Priority"
                        value={form.priority}
                        onChange={priority =>
                          setNewTaskForm(prev => ({
                            ...prev,
                            [column.id || '']: { ...form, priority: priority as 'low' | 'medium' | 'high' },
                          }))
                        }
                        options={[
                          { value: 'low', label: 'Low' },
                          { value: 'medium', label: 'Medium' },
                          { value: 'high', label: 'High' },
                        ]}
                        size="sm"
                      />
                      <Row gap="var(--ggui-spacing-2)" justify="end">
                        <Button
                          variant="ghost"
                          size="sm"
                          onClick={() =>
                            setNewTaskForm(prev => {
                              const next = { ...prev };
                              delete next[column.id || ''];
                              return next;
                            })
                          }
                        >
                          Cancel
                        </Button>
                        <Button
                          variant="primary"
                          size="sm"
                          onClick={() => handleAddTask(column.id || '')}
                        >
                          Add
                        </Button>
                      </Row>
                    </Stack>
                  )}
                </Stack>
              </Box>
            );
          })}
        </Row>
      </Stack>
    </Container>
  );
}

