            const isSelected = selectedElement?.atomicNumber === element.atomicNumber;

            return (
              <Card
                key={element.atomicNumber}
                as={Clickable}
                onClick={() => handleElementClick(element)}
                padding="var(--ggui-spacing-2)"
                shadow="sm"
                border={isSelected}
                style={{
                  gridRow: element.row,
                  gridColumn: element.col,
                  background: colors.bg,
