}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user clicks Add to Cart. Payload: { productId, quantity } */
type ActionAddToCartPayload = { productId: string; quantity: number };





// Helper component to render star rating
function StarRating({ rating, size = 20 }: { rating: number; size?: number }) {
  const fullStars = Math.floor(rating);
  const hasHalfStar = rating % 1 !== 0;
  return (
    <Row gap="var(--ggui-spacing-1)" align="center">
      {[1, 2, 3, 4, 5].map((star) => (
        <Icon
          key={star}
          name={star <= fullStars ? '★' : '☆'}
          size={size}
          color={star <= fullStars ? 'var(--ggui-color-warning-500)' : 'var(--ggui-color-outlineVariant)'}
        />
      ))}
      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{rating.toFixed(1)}</Text>
    </Row>
  );
}


export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const addToCart = useAction<ActionAddToCartPayload>('addToCart'); // Called when user clicks Add to Cart. Payload: { productId, quantity }

  // State for quantity selection and active tab
  const [quantity, setQuantity] = useState(1);
  const [activeTab, setActiveTab] = useState('description');

  // Handlers
  const handleQuantityChange = useCallback((delta: number) => {
    setQuantity((prev) => {
      const newQty = prev + delta;
      const max = props.product.stock || 0;
      return Math.max(1, Math.min(newQty, max));
    });
  }, [props.product.stock]);

  const handleAddToCart = useCallback(() => {
    if (props.product.id) {
      addToCart({ productId: props.product.id, quantity });
    }
  }, [props.product.id, quantity, addToCart]);

  // Determine stock status
  const stockStatus = props.product.stock === 0 ? 'out-of-stock' : props.product.stock && props.product.stock <= 5 ? 'low-stock' : 'in-stock';
  const isOutOfStock = stockStatus === 'out-of-stock';

  // Format price with currency
  const formattedPrice = props.product.price
    ? `${props.product.currency || '$'}${props.product.price.toFixed(2)}`
    : 'N/A';

  // Parse specifications as array of objects or strings
  const specifications = Array.isArray(props.product.specifications)
    ? props.product.specifications
    : [];

  // Parse reviews as array of objects
  const reviews = Array.isArray(props.product.reviews)
    ? props.product.reviews
    : [];

  // Tab items for tab navigation
  const tabItems = [
    {
      key: 'description',
      label: 'Description',
      content: (
        <Stack gap="var(--ggui-spacing-4)" padding="var(--ggui-spacing-4)">
          <Text variant="body" color="var(--ggui-color-onSurface)">
            {props.product.description || 'No description available.'}
          </Text>
        </Stack>
      ),
    },
    {
      key: 'specifications',
      label: 'Specifications',
      content: (
        <Box padding="var(--ggui-spacing-4)">
          {specifications.length > 0 ? (
            <Stack gap="var(--ggui-spacing-3)">
              {specifications.map((spec, idx) => {
                const specStr = typeof spec === 'string' ? spec : JSON.stringify(spec);
                const [key, value] = specStr.includes(':') ? specStr.split(':').map(s => s.trim()) : [specStr, ''];
                return (
                  <Row key={idx} justify="between" gap="var(--ggui-spacing-4)">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                      {key}
                    </Text>
                    <Text variant="body" color="var(--ggui-color-onSurface)">
                      {value}
                    </Text>
                  </Row>
                );
              })}
            </Stack>
          ) : (
            <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
              No specifications available.
            </Text>
          )}
        </Box>
      ),
    },
    {
      key: 'reviews',
      label: 'Reviews',
      content: (
        <Stack gap="var(--ggui-spacing-4)" padding="var(--ggui-spacing-4)">
          {reviews.length > 0 ? (
            reviews.map((review: any, idx) => (
              <Card key={idx} padding="var(--ggui-spacing-3)" border shadow="sm">
                <Stack gap="var(--ggui-spacing-2)">
                  <Row justify="between" align="center">
                    <Text variant="label" weight="semibold" color="var(--ggui-color-onSurface)">
                      {review.author || 'Anonymous'}
                    </Text>
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                      {review.date ? new Date(review.date).toLocaleDateString() : 'No date'}
                    </Text>
                  </Row>
                  <Row gap="var(--ggui-spacing-1)" align="center">
                    {[1, 2, 3, 4, 5].map((star) => (
                      <Icon
                        key={star}
                        name={star <= (review.rating || 0) ? '★' : '☆'}
                        size={16}
                        color={star <= (review.rating || 0) ? 'var(--ggui-color-warning-500)' : 'var(--ggui-color-outlineVariant)'}
                      />
                    ))}
                  </Row>
                  <Text variant="body" color="var(--ggui-color-onSurface)">
                    {review.text || review.content || 'No review text provided.'}
                  </Text>
                </Stack>
              </Card>
            ))
          ) : (
            <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
              No reviews yet.
            </Text>
          )}
        </Stack>
      ),
    },
  ];

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-8)">
        {/* TOP SECTION: Image + Product Info */}
        <Stack direction="horizontal" gap="var(--ggui-spacing-6)" align="start" wrap>
          {/* Product Image Placeholder */}
          <Box
            background="var(--ggui-color-primary-100)"
            borderRadius="var(--ggui-shape-radius-lg)"
            padding="var(--ggui-spacing-6)"
            style={{
              minWidth: '300px',
              width: '100%',
              maxWidth: '400px',
              aspectRatio: '1 / 1',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
            }}
          >
            <Stack align="center" gap="var(--ggui-spacing-2)">
              <Icon name="image" size={48} color="var(--ggui-color-primary-600)" />
              <Text variant="label" color="var(--ggui-color-primary-700)" align="center">
                {props.product.name || 'Product Image'}
              </Text>
            </Stack>
          </Box>

          {/* Product Details */}
          <Stack gap="var(--ggui-spacing-4)" style={{ flex: 1, minWidth: '280px' }}>
            {/* Title */}
            <Heading level={1} color="var(--ggui-color-onSurface)">
              {props.product.name || 'Product Name'}
            </Heading>

            {/* Price */}
            <Heading level={3} color="var(--ggui-color-primary-600)">
              {formattedPrice}
            </Heading>

            {/* Rating & Review Count */}
            <Row gap="var(--ggui-spacing-3)" align="center">
              <StarRating rating={props.product.rating || 0} size={20} />
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                ({props.product.reviewCount || 0} reviews)
              </Text>
            </Row>

            {/* Stock Status Badge */}
            <div>
              <Badge
                variant={stockStatus === 'low-stock' ? 'warning' : stockStatus === 'in-stock' ? 'success' : 'error'}
                size="md"
              >
                {stockStatus === 'low-stock'
                  ? 'Low Stock'
                  : stockStatus === 'in-stock'
                  ? 'In Stock'
                  : 'Out of Stock'}
              </Badge>
            </div>
          </Stack>
        </Stack>

        {/* MIDDLE SECTION: Tabs */}
        <Tabs
          items={tabItems}
          activeKey={activeTab}
          onChange={setActiveTab}
          variant="line"
          size="md"
        />

        {/* BOTTOM SECTION: Quantity & Add to Cart */}
        <Card padding="var(--ggui-spacing-6)" shadow="md">
          <Stack gap="var(--ggui-spacing-4)">
            {/* Quantity Selector */}
            <Stack gap="var(--ggui-spacing-3)">
              <Text variant="label" color="var(--ggui-color-onSurface)">
                Quantity
              </Text>
              <Row gap="var(--ggui-spacing-2)" align="center">
                <Button
                  variant="outline"
                  size="sm"
                  onClick={() => handleQuantityChange(-1)}
                  disabled={quantity <= 1}
                >
                  −
                </Button>
                <Box
                  padding="var(--ggui-spacing-2)"
                  style={{
                    minWidth: '60px',
                    textAlign: 'center',
                    border: '1px solid var(--ggui-color-outline)',
                    borderRadius: 'var(--ggui-shape-radius-md)',
                  }}
                >
                  <Text variant="body" color="var(--ggui-color-onSurface)">
                    {quantity}
                  </Text>
                </Box>
                <Button
                  variant="outline"
                  size="sm"
                  onClick={() => handleQuantityChange(1)}
                  disabled={quantity >= (props.product.stock || 0)}
                >
                  +
                </Button>
              </Row>
            </Stack>

            {/* Add to Cart Button */}
            <Button
              variant="primary"
              size="lg"
              fullWidth
              onClick={handleAddToCart}
              disabled={isOutOfStock}
            >
              {isOutOfStock ? 'Out of Stock' : 'Add to Cart'}
            </Button>
          </Stack>
        </Card>
      </Stack>
    </Container>
  );
}
}

