  const message = useStream<StreamMessage>('message'); // New message from another participant — append to message list
  const typing = useStream<StreamTyping>('typing'); // Typing indicator — show/hide based on active flag

  // State for messages and input
  const [allMessages, setAllMessages] = useState(props.messages || []);
  const [inputValue, setInputValue] = useState('');
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const messageListRef = useRef<HTMLDivElement>(null);

  // Append new messages from stream
  useEffect(() => {
    if (message.latest) {
      setAllMessages((prev) => [...prev, message.latest!]);
    }
  }, [message.latest]);

  // Auto-scroll to bottom when new messages arrive
  useEffect(() => {
    if (messagesEndRef.current) {
      messagesEndRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  }, [allMessages]);

  // Get active typing indicator (if any user is currently typing)
  const typingUser = useMemo(() => {
    if (typing.latest && typing.latest.active && typing.latest.sender) {
      return typing.latest.sender;
    }
    return null;
  }, [typing.latest]);

  // Handle sending a message
  const handleSendMessage = useCallback(() => {
    if (inputValue.trim()) {
      const payload: ActionSendMessagePayload = {
        text: inputValue,
        timestamp: new Date().toISOString(),
      };
      sendMessage(payload);
      setInputValue('');
    }
  }, [inputValue, sendMessage]);

  // Send on Enter key
  const handleKeyDown = useCallback(
    (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
      if (e.key === 'Enter' && !e.shiftKey) {
        e.preventDefault();
        handleSendMessage();
      }
    },
    [handleSendMessage]
  );

  // Group consecutive messages from same sender
  const groupedMessages = useMemo(() => {
    const groups: Array<{ sender?: string; messages: Array<{ sender?: string; text?: string; timestamp?: string }> }> = [];
    let currentGroup: { sender?: string; messages: Array<{ sender?: string; text?: string; timestamp?: string }> } | null = null;

    for (const msg of allMessages) {
      if (!currentGroup || currentGroup.sender !== msg.sender) {
        if (currentGroup) {
          groups.push(currentGroup);
        }
        currentGroup = { sender: msg.sender, messages: [msg] };
      } else {
        currentGroup.messages.push(msg);
      }
    }
    if (currentGroup) {
      groups.push(currentGroup);
    }
    return groups;
  }, [allMessages]);

  // Format timestamp
  const formatTime = useCallback((timestamp?: string) => {
    if (!timestamp) return '';
    try {
      const date = new Date(timestamp);
      return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
