                    <Text variant='label' color='var(--ggui-color-primary-700)'>
                      {typingUser} is typing
                    </Text>
                  </Row>
                </Badge>
              )}
            </Row>
          </Box>

          <Divider margin='0' color='var(--ggui-color-outline)' />

          {/* Message List */}
          <Box
            paddingX='var(--ggui-spacing-4)'
            paddingY='var(--ggui-spacing-4)'
            background='var(--ggui-color-surface)'
            style={{
              flex: 1,
              overflowY: 'auto',
              minHeight: '400px',
              display: 'flex',
              flexDirection: 'column',
              gap: 'var(--ggui-spacing-4)',
            }}
            ref={messageListRef}
          >
            {groupedMessages.length === 0 ? (
              <Box
                style={{
                  display: 'flex',
                  alignItems: 'center',
