                return (
                  <Stack
                    key={groupIdx}
                    direction='vertical'
                    gap='var(--ggui-spacing-2)'
                    align={isCurrentUser ? 'end' : 'start'}
                    style={{ maxWidth: '70%', marginLeft: isCurrentUser ? 'auto' : 0 }}
                  >
