export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract

  // Streams — real-time from agent (.latest, .all)
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate'); // Updated price data for one or more stocks
  const marketStatus = useStream<StreamMarketStatus>('marketStatus'); // Market open/closed status update

  // State for merged stock data and last update time
  const [stocks, setStocks] = useState(props.stocks);
  const [lastUpdated, setLastUpdated] = useState<Date>(new Date());
  const [updatingSymbols, setUpdatingSymbols] = useState<Set<string>>(new Set());

  // Merge price updates from stream into displayed stocks
  useEffect(() => {
    if (priceUpdate.latest) {
      const update = priceUpdate.latest;
      setStocks((prevStocks) => {
        return prevStocks.map((stock) => {
          if (stock.symbol === update.symbol) {
            // Mark this stock as updating for animation
            setUpdatingSymbols((prev) => new Set(prev).add(update.symbol!));
            // Clear the updating flag after animation
            setTimeout(() => {
              setUpdatingSymbols((prev) => {
                const next = new Set(prev);
                next.delete(update.symbol!);
                return next;
              });
            }, 600);

            return {
              ...stock,
              price: update.price ?? stock.price,
              change: update.change ?? stock.change,
              changePercent: update.changePercent ?? stock.changePercent,
            };
          }
          return stock;
        });
      });
      setLastUpdated(new Date());
    }
  }, [priceUpdate.latest]);

  // Format last updated time
  const lastUpdatedText = useMemo(() => {
    return lastUpdated.toLocaleTimeString('en-US', {
      hour: '2-digit',
      minute: '2-digit',
      second: '2-digit',
    });
  }, [lastUpdated]);

  // Market status display
  const marketStatusDisplay = useMemo(() => {
    if (!marketStatus.latest) return 'Market Closed';
    const status = marketStatus.latest.status || 'closed';
    const statusMap: Record<string, string> = {
      'open': 'Market Open',
      'closed': 'Market Closed',
      'pre-market': 'Pre-Market',
      'after-hours': 'After Hours',
    };
    return statusMap[status] || 'Market Closed';
  }, [marketStatus.latest]);

  const isMarketOpen = marketStatus.latest?.status === 'open';

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Header with title and timestamp */}
        <Row gap="var(--ggui-spacing-4)" justify="between" align="center">
          <Heading level={1} color="var(--ggui-color-onSurface)">
            Market Watch
          </Heading>
          <Stack gap="var(--ggui-spacing-2)" align="end">
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
              Last Updated: {lastUpdatedText}
            </Text>
            <Badge variant={isMarketOpen ? 'success' : 'default'} size="sm">
              {marketStatusDisplay}
            </Badge>
          </Stack>
        </Row>

        {/* Stock cards grid - responsive: 3 columns on desktop, 1 on mobile */}
        <Box
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))',
            gap: 'var(--ggui-spacing-4)',
          } as React.CSSProperties}
        >
          {stocks && stocks.length > 0 ? (
            stocks.map((stock) => (
              <StockCard
                key={stock.symbol || `stock-${Math.random()}`}
                ticker={stock.symbol || 'N/A'}
                name={stock.name || 'Unknown Company'}
                price={stock.price ?? 0}
                change={stock.change ?? 0}
                changePercent={stock.changePercent ?? 0}
                isUpdating={updatingSymbols.has(stock.symbol || '')}
              />
            ))
          ) : (
            <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
              No stocks available
            </Text>
          )}
        </Box>
      </Stack>
    </Container>
  );
}

