interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





// Place helper components here if needed

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object

  const [step, setStep] = useState(1);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState('');
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');
  const [touchedName, setTouchedName] = useState(false);
  const [touchedEmail, setTouchedEmail] = useState(false);
  const [submitted, setSubmitted] = useState(false);

  const totalSteps = 5;
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  const isNameValid = name.trim().length > 0;
  const isEmailValid = emailRegex.test(email.trim());
  const nameError = touchedName && !isNameValid ? 'Name is required.' : '';
  const emailError = touchedEmail && !isEmailValid ? 'Enter a valid email address.' : '';

  const satisfactionOptions = useMemo(
    () =>
      (props.satisfactionLabels || []).map((label, index) => ({
        label,
        value: String(index + 1),
      })),
    [props.satisfactionLabels],
  );

  const isCurrentStepValid = useMemo(() => {
    if (step === 1) return isNameValid && isEmailValid;
    if (step === 2) return satisfaction !== '';
    if (step === 3) return true;
    if (step === 4) return comments.length <= 500;
    if (step === 5) return true;
  }, [step, isNameValid, isEmailValid, satisfaction, comments]);

  const progressValue = (step / totalSteps) * 100;

  const toggleFeature = useCallback((feature: string, checked: boolean) => {
    setFeatures((prev) => {
      if (checked) {
        if (prev.includes(feature)) return prev;
        return [...prev, feature];
      }
      return prev.filter((item) => item !== feature);
    });
  }, []);

  const handleNext = useCallback(() => {
    if (step === 1) {
      setTouchedName(true);
      setTouchedEmail(true);
      if (!isNameValid || !isEmailValid) return;
    }
    if (step === 2 && satisfaction === '') return;
    if (step < totalSteps) setStep((prev) => prev + 1);
  }, [step, isNameValid, isEmailValid, satisfaction, totalSteps]);

  const handleBack = useCallback(() => {
    if (step > 1) setStep((prev) => prev - 1);
  }, [step]);

  const handleSubmit = useCallback(() => {
    if (!isNameValid || !isEmailValid || satisfaction === '') return;
    const payload = {
      name: name.trim(),
      email: email.trim(),
      satisfaction: Number(satisfaction),
      features,
      comments: comments.trim(),
    };
    submit(payload);
    if ((props as Props & { onSubmit?: (data: ActionSubmitPayload) => void }).onSubmit) {
      (props as Props & { onSubmit: (data: ActionSubmitPayload) => void }).onSubmit(payload);
    }
    setSubmitted(true);
  }, [isNameValid, isEmailValid, satisfaction, name, email, features, comments, submit, props]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-4)" border shadow="sm">
          <Stack gap="var(--ggui-spacing-3)">
            <Row justify="between" align="center">
              <Heading level={4}>Survey</Heading>
              <Badge variant="primary">Step {step} of {totalSteps}</Badge>
            </Row>
            <Progress value={progressValue} max={100} size="md" />
          </Stack>
        </Card>

        <Card padding="var(--ggui-spacing-6)" border shadow="sm">
          <Stack gap="var(--ggui-spacing-4)">
            {step === 1 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={5}>Your details</Heading>
                <Input
                  label="Name"
                  value={name}
                  onChange={setName}
                  required
                  error={nameError}
                  placeholder="Enter your name"
                  onBlur={() => setTouchedName(true)}
                />
                <Input
                  label="Email"
                  type="email"
                  value={email}
                  onChange={setEmail}
                  required
                  error={emailError}
                  placeholder="Enter your email"
                  onBlur={() => setTouchedEmail(true)}
                />
              </Stack>
            )}

            {step === 2 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={5}>Satisfaction rating</Heading>
                <RadioGroup
                  label="How satisfied are you?"
                  value={satisfaction}
                  onChange={setSatisfaction}
                  options={satisfactionOptions}
                  direction="vertical"
                  error={satisfaction === '' ? 'Please choose a rating to continue.' : undefined}
                />
              </Stack>
            )}

            {step === 3 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={5}>Feature interests</Heading>
                <Text color="var(--ggui-color-onSurfaceVariant)">Select all that apply.</Text>
                {(props.featureOptions || []).length === 0 ? (
                  <Alert variant="info">No feature options available.</Alert>
                ) : (
                  <Stack gap="var(--ggui-spacing-2)">
                    {(props.featureOptions || []).map((feature) => (
                      <Checkbox
                        key={feature}
                        label={feature}
                        checked={features.includes(feature)}
                        onChange={(checked) => toggleFeature(feature, checked)}
                      />
                    ))}
                  </Stack>
                )}
              </Stack>
            )}

            {step === 4 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={5}>Additional comments</Heading>
                <TextArea
                  label="Additional comments (optional)"
                  value={comments}
                  onChange={setComments}
                  placeholder="Share any additional feedback (optional)"
                  rows={6}
                  maxLength={500}
                  showCount
                />
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                  {comments.length}/500 characters
                </Text>
              </Stack>
            )}

            {step === 5 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={5}>Review your responses</Heading>
                <Card padding="var(--ggui-spacing-4)" background="var(--ggui-color-surfaceVariant)">
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text><Text is="span" weight="semibold">Name:</Text> {name || '—'}</Text>
                    <Text><Text is="span" weight="semibold">Email:</Text> {email || '—'}</Text>
                    <Text>
                      <Text is="span" weight="semibold">Satisfaction:</Text>{' '}
                      {satisfaction !== '' && props.satisfactionLabels[Number(satisfaction) - 1]
                        ? `${satisfaction} - ${props.satisfactionLabels[Number(satisfaction) - 1]}`
                        : '—'}
                    </Text>
                    <Text>
                      <Text is="span" weight="semibold">Features:</Text>{' '}
                      {features.length > 0 ? features.join(', ') : 'None selected'}
                    </Text>
                    <Text><Text is="span" weight="semibold">Comments:</Text> {comments.trim() || 'None'}</Text>
                  </Stack>
                </Card>
                {submitted && <Alert variant="success">Responses submitted successfully.</Alert>}
              </Stack>
            )}

            <Divider margin="var(--ggui-spacing-2)" />
            <Row justify="between" align="center">
              <Text
                as={Clickable}
                onClick={handleBack}
                color={step === 1 ? 'var(--ggui-color-onSurfaceVariant)' : 'var(--ggui-color-primary-600)'}
              >
                Back
              </Text>
              <Row gap="var(--ggui-spacing-2)">
                {step < totalSteps ? (
                  <Button variant="primary" onClick={handleNext} disabled={!isCurrentStepValid}>
                    Next
                  </Button>
                ) : (
                  <Button variant="primary" onClick={handleSubmit}>
                    Submit
                  </Button>
                )}
              </Row>
            </Row>
          </Stack>
        </Card>
      </Stack>
    </Container>

  );
}

