    const incomingTask = taskChanged.latest.task;
    const action = taskChanged.latest.action || 'edit';
    const incomingId = incomingTask.id || '';
    if (!incomingId) return;

    setTasksState((prev) => {
      if (action === 'delete') {
        return prev.filter((t, idx) => ensureTaskId(t, idx) !== incomingId);
      }
      const existingIndex = prev.findIndex((t, idx) => ensureTaskId(t, idx) === incomingId);
      if (existingIndex === -1) {
        return [...prev, incomingTask];
      }
      const next = [...prev];
      next[existingIndex] = { ...next[existingIndex], ...incomingTask };
      return next;
    });
  }, [taskChanged.latest]);

