  }, [allColumns]);

  const doneColumnId = useMemo(() => {
    const byName = allColumns.find((c) => (c.name || '').toLowerCase() === 'done')?.id;
    return byName || allColumns[2]?.id || 'done';
  }, [allColumns]);

  const tasksByColumn = useMemo(() => {
    const map: Record<string, Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>> = {};
    allColumns.forEach((col) => {
      if (col.id) map[col.id] = [];
    });
    tasksState.forEach((task, index) => {
      const taskColumn = task.column || todoColumnId;
      if (!map[taskColumn]) map[taskColumn] = [];
      map[taskColumn].push({ ...task, id: ensureTaskId(task, index), column: taskColumn });
    });
    return map;
  }, [tasksState, allColumns, todoColumnId]);

  const totalTasks = tasksState.length;
  const completedCount = tasksState.filter((task) => (task.column || '') === doneColumnId).length;

  const moveTask = useCallback((taskId: string, nextColumn: string) => {
    setTasksState((prev) => prev.map((task, index) => (ensureTaskId(task, index) === taskId ? { ...task, column: nextColumn } : task)));
    taskUpdate({ action: 'move', taskId, data: { column: nextColumn } });
  }, [taskUpdate]);

  const startEditTask = useCallback((taskId: string, currentTitle?: string) => {
    setEditingTaskId(taskId);
    setEditingTitle(currentTitle || '');
  }, []);

  const saveEditTask = useCallback((taskId: string) => {
    const cleanTitle = editingTitle.trim();
    if (!cleanTitle) return;
    setTasksState((prev) => prev.map((task, index) => (ensureTaskId(task, index) === taskId ? { ...task, title: cleanTitle } : task)));
    taskUpdate({ action: 'edit', taskId, data: { column: (tasksState.find((t, idx) => ensureTaskId(t, idx) === taskId)?.column || todoColumnId) } });
    setEditingTaskId('');
    setEditingTitle('');
  }, [editingTitle, taskUpdate, tasksState, todoColumnId]);

  const createTask = useCallback((columnId: string) => {
    const cleanTitle = newTaskTitle.trim();
    if (!cleanTitle) return;
    const targetColumn = todoColumnId;
    const id = `new-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
    const task = {
      id,
      title: cleanTitle,
      priority: (newTaskPriority as 'low' | 'medium' | 'high') || 'medium',
      assignee: '',
      column: targetColumn,
      dueDate: '',
    };
    setTasksState((prev) => [...prev, task]);
    taskUpdate({ action: 'create', taskId: id, data: { column: targetColumn } });
    setAddingColumnId('');
    setNewTaskTitle('');
    setNewTaskPriority('medium');
  }, [newTaskTitle, newTaskPriority, todoColumnId, taskUpdate]);

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-4)">
        <Card padding="var(--ggui-spacing-4)" border shadow="sm">
          <Row justify="between" align="center">
            <Stack gap="var(--ggui-spacing-1)">
              <Heading level={2}>Team Kanban Board</Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                Live updates: {taskChanged.all.length}
              </Text>
            </Stack>
            <Row gap="var(--ggui-spacing-3)">
              <Badge variant="primary">Total: {totalTasks}</Badge>
              <Badge variant="success">Completed: {completedCount}</Badge>
            </Row>
          </Row>
        </Card>

        {allColumns.length === 0 && (
          <Alert variant="warning" title="No columns configured">
            Add columns in props.columns to display the board.
          </Alert>
        )}

        <Stack direction="horizontal" gap="var(--ggui-spacing-4)" wrap>
          {allColumns.map((column) => {
            const columnId = column.id || '';
            const columnTasks = columnId ? (tasksByColumn[columnId] || []) : [];
            return (
              <Card
                key={columnId || column.name}
                padding="var(--ggui-spacing-4)"
                shadow="sm"
                border
              >
                <Stack gap="var(--ggui-spacing-3)">
                  <Row justify="between" align="center">
                    <Heading level={4}>{column.name || 'Untitled'}</Heading>
                    <Badge variant="default">{columnTasks.length}</Badge>
                  </Row>

                  <Stack gap="var(--ggui-spacing-2)">
                    {columnTasks.length === 0 ? (
                      <Box padding="var(--ggui-spacing-3)" background="var(--ggui-color-surfaceVariant)" borderRadius="var(--ggui-shape-radius-md)">
                        <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                          No tasks yet
                        </Text>
                      </Box>
                    ) : (
                      columnTasks.map((task, taskIndex) => {
                        const taskId = ensureTaskId(task, taskIndex);
                        const canEdit = editingTaskId === taskId;
                        return (
                          <Card key={taskId} padding="var(--ggui-spacing-3)" border shadow="none">
                            <Stack gap="var(--ggui-spacing-2)">
                              <Row justify="between" align="start">
                                <Box>
                                  {canEdit ? (
                                    <Stack gap="var(--ggui-spacing-2)">
                                      <Input
                                        label="Edit task title"
                                        value={editingTitle}
                                        onChange={setEditingTitle}
                                        placeholder="Task title"
                                      />
                                      <Row gap="var(--ggui-spacing-2)">
                                        <Button as={Clickable} onClick={() => saveEditTask(taskId)} size="sm" variant="primary">Save</Button>
                                        <Button as={Clickable} onClick={() => { setEditingTaskId(''); setEditingTitle(''); }} size="sm" variant="ghost">Cancel</Button>
                                      </Row>
                                    </Stack>
                                  ) : (
                                    <Text
                                      as={Clickable}
                                      onDoubleClick={() => startEditTask(taskId, task.title)}
                                      variant="label"
                                      color="var(--ggui-color-onSurface)"
                                    >
                                      {task.title || 'Untitled task'}
                                    </Text>
                                  )}
                                </Box>
                                {!canEdit && (
                                  <Button as={Clickable} onClick={() => startEditTask(taskId, task.title)} size="xs" variant="ghost">Edit</Button>
                                )}
                              </Row>

                              <Row justify="between" align="center">
                                <Badge variant={getPriorityBadgeVariant(task.priority)}>{task.priority || 'low'}</Badge>
                                {task.assignee ? (
                                  <Avatar name={task.assignee} size="sm" />
                                ) : (
                                  <Avatar name="Unassigned" size="sm" />
                                )}
                              </Row>

                              {task.dueDate ? (
                                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                                  Due: {formatDueDate(task.dueDate)}
                                </Text>
                              ) : (
                                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                                  No due date
                                </Text>
                              )}

                              <Select
                                label="Move task"
                                value={task.column || todoColumnId}
                                onChange={(value) => moveTask(taskId, value)}
                                options={allColumns.map((c) => ({ value: c.id || '', label: c.name || 'Untitled' }))}
                              />
                            </Stack>
                          </Card>
                        );
                      })
                    )}
                  </Stack>

                  {addingColumnId === columnId ? (
                    <Card padding="var(--ggui-spacing-3)" border shadow="none">
                      <Stack gap="var(--ggui-spacing-2)">
                        <Input
                          label="Task title"
                          value={newTaskTitle}
                          onChange={setNewTaskTitle}
                          placeholder="Enter task title"
                        />
                        <Select
                          label="Priority"
                          value={newTaskPriority}
                          onChange={setNewTaskPriority}
                          options={PRIORITY_OPTIONS}
                        />
                        <Row gap="var(--ggui-spacing-2)">
                          <Button as={Clickable} onClick={() => createTask(columnId)} size="sm" variant="primary">Create</Button>
                          <Button
                            as={Clickable}
                            onClick={() => {
                              setAddingColumnId('');
                              setNewTaskTitle('');
                              setNewTaskPriority('medium');
                            }}
                            size="sm"
                            variant="ghost"
                          >
                            Cancel
                          </Button>
                        </Row>
                      </Stack>
                    </Card>
                  ) : (
                    <Button as={Clickable} onClick={() => setAddingColumnId(columnId)} variant="outline">Add Task</Button>
                  )}
                </Stack>
              </Card>
            );
          })}
        </Stack>
      </Stack>
    </Container>

  );
}

