}





type ElementItem = {
  atomicNumber?: number;
  symbol?: string;
  name?: string;
  atomicWeight?: number;
  category?: string;
  row?: number;
  col?: number;
};

const categoryColorMap: Record<string, string> = {
  'alkali metal': 'var(--ggui-color-error-100)',
  'alkaline earth metal': 'var(--ggui-color-warning-100)',
  'transition metal': 'var(--ggui-color-primary-100)',
  lanthanide: 'var(--ggui-color-success-100)',
  actinide: 'var(--ggui-color-info-100)',
  metalloid: 'var(--ggui-color-primary-200)',
  'post-transition metal': 'var(--ggui-color-surfaceVariant)',
  nonmetal: 'var(--ggui-color-success-50)',
  halogen: 'var(--ggui-color-warning-200)',
  'noble gas': 'var(--ggui-color-info-200)',
  'noble-gas': 'var(--ggui-color-info-200)',
  unknown: 'var(--ggui-color-outlineVariant)',
};

function getCategoryColor(category?: string): string {
  if (!category) return categoryColorMap.unknown;
  const normalized = category.trim().toLowerCase();
  return categoryColorMap[normalized] || 'var(--ggui-color-primary-50)';
}

function getElementKey(element: ElementItem, index: number): string {
  return `${element.atomicNumber ?? 'x'}-${element.symbol ?? 'na'}-${index}`;
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract

  const [searchQuery, setSearchQuery] = useState<string>('');
  const [selectedElementIndex, setSelectedElementIndex] = useState<number>(-1);

  const safeElements = useMemo(() => {
    return Array.isArray(props.elements) ? props.elements : [];
  }, [props.elements]);

  const filteredElements = useMemo(() => {
    const query = searchQuery.trim().toLowerCase();
    if (!query) return safeElements;
    return safeElements.filter((element) => {
      const name = (element.name || '').toLowerCase();
      const symbol = (element.symbol || '').toLowerCase();
      return name.includes(query) || symbol.includes(query);
    });
  }, [safeElements, searchQuery]);

  const selectedElement = useMemo(() => {
    if (selectedElementIndex < 0 || selectedElementIndex >= filteredElements.length) return null;
    return filteredElements[selectedElementIndex] || null;
  }, [filteredElements, selectedElementIndex]);

  useEffect(() => {
    if (!filteredElements.length) {
      setSelectedElementIndex(-1);
      return;
    }
    if (selectedElementIndex >= filteredElements.length) {
      setSelectedElementIndex(0);
    }
  }, [filteredElements, selectedElementIndex]);

  const categories = useMemo(() => {
    const set = new Set<string>();
    safeElements.forEach((element) => {
      const label = (element.category || 'unknown').trim() || 'unknown';
      set.add(label);
    });
    return Array.from(set).sort((a, b) => a.localeCompare(b));
  }, [safeElements]);

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Heading level={2}>Interactive Periodic Table</Heading>

        <Input
          label="Search elements"
          placeholder="Type element name or symbol"
          value={searchQuery}
          onChange={setSearchQuery}
        />

        {!safeElements.length ? (
          <Alert variant="warning" title="No element data">
            No elements were provided in props.elements.
          </Alert>
        ) : (
          <Card padding="var(--ggui-spacing-4)" shadow="sm" border>
            <Box
              style={{
                display: 'grid',
                gridTemplateColumns: 'repeat(18, minmax(0, 1fr))',
                gap: 'var(--ggui-spacing-2)',
                overflowX: 'auto',
              }}
            >
              {filteredElements.map((element, index) => (
                <Card
                  key={getElementKey(element, index)}
                  as={Clickable}
                  onClick={() => setSelectedElementIndex(index)}
                  padding="var(--ggui-spacing-2)"
                  shadow="none"
                  border
                  style={{
                    gridColumn: `${element.col || 1} / span 1`,
                    gridRow: `${element.row || 1} / span 1`,
                    minHeight: '72px',
                    background: getCategoryColor(element.category),
                    borderColor: selectedElementIndex === index ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-outline)',
                    borderWidth: selectedElementIndex === index ? '2px' : '1px',
                    borderStyle: 'solid',
                  }}
                >
                  <Stack gap="var(--ggui-spacing-1)">
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                      {element.atomicNumber ?? '-'}
                    </Text>
                    <Text align="center" size="xl" weight="bold">
                      {element.symbol || '?'}
                    </Text>
                  </Stack>
                </Card>
              ))}
            </Box>
          </Card>
        )}

        {!filteredElements.length && safeElements.length ? (
          <Alert variant="info" title="No matches">
            No elements match your search. Try another name or symbol.
          </Alert>
        ) : null}

        <Card padding="var(--ggui-spacing-4)" border>
          <Stack gap="var(--ggui-spacing-2)">
            <Heading level={4}>Selected Element Details</Heading>
            {selectedElement ? (
              <Stack gap="var(--ggui-spacing-1)">
                <Text><Text is="span" weight="semibold">Name:</Text> {selectedElement.name || '-'}</Text>
                <Text><Text is="span" weight="semibold">Symbol:</Text> {selectedElement.symbol || '-'}</Text>
                <Text><Text is="span" weight="semibold">Atomic Number:</Text> {selectedElement.atomicNumber ?? '-'}</Text>
                <Text><Text is="span" weight="semibold">Atomic Weight:</Text> {selectedElement.atomicWeight ?? '-'}</Text>
                <Text><Text is="span" weight="semibold">Category:</Text> {selectedElement.category || 'unknown'}</Text>
              </Stack>
            ) : (
              <Text color="var(--ggui-color-onSurfaceVariant)">
                Select an element to view details.
              </Text>
            )}
          </Stack>
        </Card>

        <Card padding="var(--ggui-spacing-4)" border>
          <Stack gap="var(--ggui-spacing-3)">
            <Heading level={4}>Category Legend</Heading>
            <Row gap="var(--ggui-spacing-2)" wrap>
              {categories.map((category) => (
                <Row key={category} gap="var(--ggui-spacing-2)" align="center">
                  <Box
                    style={{
                      width: '14px',
                      height: '14px',
