                      background: getCategoryColor(category),
                      border: '1px solid var(--ggui-color-outline)',
                    }}
                  />
                  <Text variant="bodySmall">{category}</Text>
                </Row>
              ))}
            </Row>
          </Stack>
        </Card>
      </Stack>
    </Container>

  );
