  const safeRating = Math.max(0, Math.min(5, Math.round(rating ?? 0)));
  return Array.from({ length: 5 }).map((_, index) => (
    <Text
      key={`star-${index}`}
>
      {index < safeRating ? '★' : '☆'}
    </Text>
  ));
};

