            <Row gap="var(--ggui-spacing-2)" align="center">
              <Text weight="medium">Quantity</Text>
              <Text
                as={Clickable}
                onClick={handleDecrease}
                color="var(--ggui-color-primary-700)"
>
                −
              </Text>
              <Input
                label="Selected quantity"
                value={String(quantity)}
                onChange={(value) => {
                  const parsed = Number(value);
                  if (Number.isNaN(parsed)) return;
                  const safeMax = maxStock > 0 ? maxStock : 1;
                  setQuantity(Math.max(1, Math.min(safeMax, parsed)));
                }}
                type="number"
