    setAllMessages(props.messages ?? []);
  }, [props.messages]);

  useEffect(() => {
    if (message.latest) {
      setAllMessages((prev) => [...prev, message.latest as StreamMessage]);
    }
  }, [message.latest]);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [allMessages]);

  const typingSender = useMemo(() => {
    if (!typing.latest?.active) {
      return '';
