              borderRadius="var(--ggui-shape-radius-md)"
              padding="var(--ggui-spacing-3)"
            >
              <Stack gap="var(--ggui-spacing-3)">
                <Box>
                  <div
                    ref={scrollRef}
                    style={{
                      maxHeight: '60vh',
                      overflowY: 'auto',
                      padding: 'var(--ggui-spacing-2)',
                      background: 'var(--ggui-color-surface)',
                      borderRadius: 'var(--ggui-shape-radius-md)',
                    }}
                  >
                    {(groupedMessages ?? []).length === 0 ? (
                      <Text color="var(--ggui-color-onSurfaceVariant)">No messages yet.</Text>
                    ) : (
                      <Stack gap="var(--ggui-spacing-3)">
                        {(groupedMessages ?? []).map((group, groupIndex) => {
                          const isCurrentUser = group.sender === props.currentUser;
                          return (
                            <Stack
                              key={`${String(group.sender)}-${groupIndex}`}
                              gap="var(--ggui-spacing-1)"
                              align={isCurrentUser ? 'end' : 'start'}
>
                              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                                {group.sender || 'Unknown'}
                              </Text>
                              {(group.items ?? []).map((msg, msgIndex) => (
                                <Box
                                  key={`${String(group.sender)}-${groupIndex}-${msgIndex}`}
                                  padding="var(--ggui-spacing-2)"
                                  background={isCurrentUser ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-surfaceVariant)'}
                                  borderRadius="var(--ggui-shape-radius-md)"
                                >
                                  <Stack gap="var(--ggui-spacing-1)">
                                    <Text
                                      color={isCurrentUser ? 'var(--ggui-color-onContainer)' : 'var(--ggui-color-onSurface)'}
                                    >
                                      {msg.text || ''}
                                    </Text>
                                    <Text
                                      variant="caption"
                                      color={isCurrentUser ? 'var(--ggui-color-onContainer)' : 'var(--ggui-color-onSurfaceVariant)'}
                                      align={isCurrentUser ? 'right' : 'left'}
                                    >
                                      {formatTimestamp(msg.timestamp)}
                                    </Text>
                                  </Stack>
                                </Box>
                              ))}
                            </Stack>
                          );
                        })}
                      </Stack>
                    )}
                  </div>
                </Box>

                <Divider margin="var(--ggui-spacing-2)" />

                <Row gap="var(--ggui-spacing-2)" align="end">
                  <Box style={{ flex: 1 } as React.CSSProperties}>
                    <Input
                      label="Message"
                      placeholder="Type a message..."
                      value={draft}
                      onChange={setDraft}
                      onKeyDown={(event) => {
                        if (event.key === 'Enter') {
                          event.preventDefault();
                          handleSend();
                        }
                      }}
                    />
                  </Box>
                  <Button
                    variant="primary"
                    disabled={!draft.trim()}
                    onClick={handleSend}
                  >
                    Send
                  </Button>
                </Row>
              </Stack>
            </Box>
          </Box>
        </Stack>
      </Card>
    </Container>

  );
