            </Text>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
              Current Time: {now.toLocaleTimeString()}
            </Text>
          </Stack>
          <Badge variant={marketStatusLabel === 'open' ? 'success' : marketStatusLabel === 'closed' ? 'error' : 'warning'}>
            {marketStatusLabel}
          </Badge>
        </Row>

        {stocksState.length === 0 ? (
          <Card padding="var(--ggui-spacing-6)" border radius="lg">
            <Stack gap="var(--ggui-spacing-2)" align="center">
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">No stocks available.</Text>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Waiting for live market data...</Text>
            </Stack>
          </Card>
        ) : (
          <Box>
            <Box
              className="stocks-grid-fixed"
              style={{
                display: 'grid',
                gridTemplateColumns: 'repeat(1, minmax(0, 1fr))',
                gap: 'var(--ggui-spacing-4)',
              }}
              >
                <style>{`@media (min-width: 1024px) { .stocks-grid-fixed { grid-template-columns: repeat(3, minmax(0, 1fr)) !important; } }`}</style>
              {stocksState.map((stock) => {
                const positive = stock.change >= 0;
                const color = positive ? 'var(--ggui-color-success-600)' : 'var(--ggui-color-error-600)';
                const flashColor = positive ? 'var(--ggui-color-success-100)' : 'var(--ggui-color-error-100)';
                const shouldFlash = typeof updatedSymbols[stock.symbol] === 'number' && Date.now() - updatedSymbols[stock.symbol] < 700;
                return (
                  <Card
                    key={stock.symbol}
                    padding="var(--ggui-spacing-4)"
                    border
                    radius="lg"
                    shadow="sm"
                  >
                    <Box
                      style={{
                        animation: shouldFlash ? 'ggui-flash 300ms ease-out' : 'none',
                        background: shouldFlash ? flashColor : 'var(--ggui-color-surfaceVariant)',
                        borderRadius: 'var(--ggui-shape-radius-md)',
                        padding: 'var(--ggui-spacing-3)',
                        border: `1px solid ${color}`,
                      }}
                    >
                    >
                      <Stack gap="var(--ggui-spacing-2)">
                        <Heading level={3} color="var(--ggui-color-onSurface)">{stock.symbol}</Heading>
                        <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">{stock.name}</Text>
                        <Text variant="bodyLarge" weight="bold" color="var(--ggui-color-onSurface)">
                          {formatPrice(stock.price)}
                        </Text>
                        <Row justify="between" align="center">
                          <Text variant="bodySmall" color={color}>
                            {formatSigned(stock.change)}
                          </Text>
                          <Text variant="bodySmall" weight="semibold" color={color}>
                            {positive ? '▲' : '▼'} {formatPercent(stock.changePercent)}
                          </Text>
                        </Row>
                      </Stack>
                    </Box>
                  </Card>
                );
              })}
