  );
  const [theme, setTheme] = useState(props.initialProfile.theme ?? 'light');
  const [showValidation, setShowValidation] = useState(false);

  const trimmedName = useMemo(() => name.trim(), [name]);
  const trimmedEmail = useMemo(() => email.trim(), [email]);
  const isEmailValid = useMemo(() => EMAIL_REGEX.test(trimmedEmail), [trimmedEmail]);
  const isStep1Valid = useMemo(() => trimmedName.length > 0 && isEmailValid, [trimmedName, isEmailValid]);
  const isStep2Valid = useMemo(() => role.trim().length > 0 && (theme === 'light' || theme === 'dark'), [role, theme]);
  const canGoNext = useMemo(() => (step === 1 ? isStep1Valid : step === 2 ? isStep2Valid : true), [step, isStep1Valid, isStep2Valid]);
  const progressValue = useMemo(() => (step / 3) * 100, [step]);
  const visibleAvatarOptions = useMemo(() => (props.avatarOptions.length > 0 ? props.avatarOptions : ['🙂', '😎', '🚀', '🎨']), [props.avatarOptions]);
  const visibleRoleOptions = useMemo(() => (props.roleOptions.length > 0 ? props.roleOptions : ['Developer', 'Designer', 'Manager', 'Other']), [props.roleOptions]);

