    setShowValidation(false);
    setStep((prev) => (prev > 1 ? prev - 1 : prev));
  }, []);

  const submit = useCallback(() => {
    const payload: ActionCompletePayload = {
      name: trimmedName,
      email: trimmedEmail,
      avatar: avatar || visibleAvatarOptions[0] || '🙂',
