                  type="email"
                  value={email}
                  onChange={setEmail}
                  placeholder="you@example.com"
                  required
                  error={showValidation && !isEmailValid ? 'Enter a valid email address' : undefined}
                />
                <Stack gap="var(--ggui-spacing-2)">
                  <Text variant="label" color="var(--ggui-color-onSurface)">Choose Avatar</Text>
                  <Row gap="var(--ggui-spacing-3)" wrap>
                    {visibleAvatarOptions.slice(0, 4).map((option) => (
                      <Card
                        key={option}
                        as={Clickable}
                        onClick={() => setAvatar(option)}
                        padding="var(--ggui-spacing-3)"
                        border
                        radius="md"
                        shadow="none"
                        style={{
                          minWidth: '56px',
                          textAlign: 'center',
                          borderColor: avatar === option ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-outline)',
                          background: avatar === option ? 'var(--ggui-color-primary-50)' : 'var(--ggui-color-surface)',
                        }}
                      >
                        <Text size="2xl" align="center">{option}</Text>
                      </Card>
                    ))}
                  </Row>
                </Stack>
              </Stack>
            )}

            {step === 2 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Preferences</Heading>
                <Select
                  label="Role"
                  value={role}
                  onChange={setRole}
                  placeholder="Select your role"
                  options={visibleRoleOptions.map((option) => ({ value: option, label: option }))}
                  required
                  error={showValidation && role.trim().length === 0 ? 'Role is required' : undefined}
                />
                <Toggle
                  label="Email Notifications"
                  checked={emailNotifications}
                  onChange={setEmailNotifications}
                  size="md"
                />
                <Stack gap="var(--ggui-spacing-2)">
                  <Text variant="label">Theme Preference</Text>
                  <Row gap="var(--ggui-spacing-3)">
                    <Button
                      variant={theme === 'light' ? 'primary' : 'outline'}
                      onClick={() => setTheme('light')}
                    >
                      Light
                    </Button>
                    <Button
                      variant={theme === 'dark' ? 'primary' : 'outline'}
                      onClick={() => setTheme('dark')}
                    >
                      Dark
                    </Button>
                  </Row>
                </Stack>
              </Stack>
            )}

            {step === 3 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Review & Confirm</Heading>
                <Card padding="var(--ggui-spacing-4)" border radius="md" shadow="none">
                  <Stack gap="var(--ggui-spacing-2)">
                    <Row justify="between"><Text variant="label">Name</Text><Text>{trimmedName || '-'}</Text></Row>
                    <Row justify="between"><Text variant="label">Email</Text><Text>{trimmedEmail || '-'}</Text></Row>
                    <Row justify="between"><Text variant="label">Avatar</Text><Text size="xl">{avatar}</Text></Row>
                    <Row justify="between"><Text variant="label">Role</Text><Text>{role || '-'}</Text></Row>
                    <Row justify="between"><Text variant="label">Email Notifications</Text><Text>{emailNotifications ? 'On' : 'Off'}</Text></Row>
                    <Row justify="between"><Text variant="label">Theme</Text><Text>{theme}</Text></Row>
                  </Stack>
                </Card>
                <Alert variant="info" title="Ready to complete?">
                  If everything looks correct, complete setup now. You can also go back to edit.
                </Alert>
              </Stack>
            )}
          </Box>

          <Divider margin="var(--ggui-spacing-4)" />

          <Row justify="between" align="center">
            <Button variant="ghost" onClick={prevStep} disabled={step === 1}>
              Back
            </Button>
            <Row gap="var(--ggui-spacing-2)">
              {step < 3 && (
                <Button variant="primary" onClick={nextStep} disabled={!canGoNext}>
                  Next
                </Button>
              )}
              {step === 3 && (
                <>
                  <Button variant="outline" onClick={prevStep}>Go Back</Button>
                  <Button variant="primary" onClick={submit}>Complete Setup</Button>
                </>
              )}
            </Row>
          </Row>
        </Card>
      </Stack>
    </Container>

  );
}
